// 处理进度追踪请求
const input = $input.first().json;

const trackingData = {
  userId: input.userId,
  pathId: input.pathId,
  action: input.action, // 'start', 'complete', 'update'
  itemType: input.itemType, // 'topic', 'phase', 'resource'
  itemId: input.itemId,
  timestamp: new Date().toISOString(),
  metadata: input.metadata || {}
};

return {
  json: {
    trackingData,
    processedAt: new Date().toISOString()
  }
};

// 计算整体进度和统计信息
const progressRecords = $input.all();
const pathData = $('获取用户进度').first().json;

// 统计完成情况
const completedItems = progressRecords.filter(r => r.json.completed === true);
const totalItems = progressRecords.length;
const progressPercentage = totalItems > 0 
  ? Math.round((completedItems.length / totalItems) * 100) 
  : 0;

// 按类型分组
const byType = {};
progressRecords.forEach(record => {
  const type = record.json.item_type;
  if (!byType[type]) {
    byType[type] = { total: 0, completed: 0 };
  }
  byType[type].total++;
  if (record.json.completed) {
    byType[type].completed++;
  }
});

// 学习时间统计
const startDate = new Date(Math.min(...progressRecords.map(r => new Date(r.json.created_at))));
const totalDays = Math.ceil((new Date() - startDate) / (1000 * 60 * 60 * 24));
const avgPerWeek = totalDays > 0 ? Math.round((completedItems.length / totalDays) * 7) : 0;

// 生成激励消息
const motivationalMessages = [
  { threshold: 0, message: "🌱 开始你的学习之旅吧！" },
  { threshold: 25, message: "💪 不错的开始，继续保持！" },
  { threshold: 50, message: "🎯 已经过半了，加油！" },
  { threshold: 75, message: "🔥 胜利在望，冲刺！" },
  { threshold: 100, message: "🏆 恭喜完成！你是最棒的！" }
];

const currentMessage = motivationalMessages
  .slice()
  .reverse()
  .find(m => progressPercentage >= m.threshold);

// 计算预估完成时间
const remainingItems = totalItems - completedItems.length;
const estimatedDaysRemaining = avgPerWeek > 0 ? Math.ceil(remainingItems / avgPerWeek) * 7 : 30;
const estimatedCompletionDate = new Date();
estimatedCompletionDate.setDate(estimatedCompletionDate.getDate() + estimatedDaysRemaining);

return {
  json: {
    status: 'success',
    progress: {
      overall: progressPercentage,
      completedItems: completedItems.length,
      totalItems: totalItems,
      byType: byType
    },
    statistics: {
      startDate: startDate.toISOString(),
      totalDays: totalDays,
      averagePerWeek: avgPerWeek,
      estimatedCompletionDate: estimatedCompletionDate.toISOString(),
      remainingDays: estimatedDaysRemaining
    },
    achievements: [
      { id: 'first_step', name: '第一步', unlocked: completedItems.length >= 1 },
      { id: 'quarter_way', name: '四分之一', unlocked: progressPercentage >= 25 },
      { id: 'halfway', name: '半途', unlocked: progressPercentage >= 50 },
      { id: 'almost_there', name: '指日可待', unlocked: progressPercentage >= 75 },
      { id: 'champion', name: '冠军', unlocked: progressPercentage >= 100 }
    ],
    motivation: currentMessage?.message || "继续前进！",
    streak: calculateStreak(progressRecords)
  }
};

function calculateStreak(records) {
  // 简化版连续学习天数计算
  const dates = [...new Set(records.map(r => new Date(r.json.created_at).toDateString()))];
  dates.sort((a, b) => new Date(b) - new Date(a));

  let streak = 0;
  const today = new Date().toDateString();
  const yesterday = new Date(Date.now() - 86400000).toDateString();

  if (dates[0] === today || dates[0] === yesterday) {
    streak = 1;
    for (let i = 1; i < dates.length; i++) {
      const prevDate = new Date(dates[i-1]);
      const currDate = new Date(dates[i]);
      const diffDays = (prevDate - currDate) / (1000 * 60 * 60 * 24);
      if (diffDays === 1) {
        streak++;
      } else {
        break;
      }
    }
  }

  return streak;
}

// 检查需要提醒的用户
const oneWeekAgo = new Date();
oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);

return {
  json: {
    type: 'reminder_check',
    checkDate: new Date().toISOString(),
    thresholdDate: oneWeekAgo.toISOString(),
    message: '检查超过 7 天未学习的用户'
  }
};

